mapper.select:
SELECT c.course_id AS courseId, c.category_type AS categoryType, c.course_type AS courseType, c.course_title AS courseTitle, c.instructor_name AS instructorName, c.thumbnail_url AS thumbnailUrl,
-- 실시간 가상 상태(Computed Status) 계산 CASE WHEN c.course_type = 'ONLINE' THEN CASE WHEN onc.status = 'CANCELED' THEN '서비스 종료' ELSE '상시 수강 가능' END WHEN c.course_type = 'OFFLINE' THEN CASE WHEN ofc.status = 'CANCELED' THEN '폐강' -- MyBatis XML에서는 부등호를 < 와 > 로 치환해야 오류가 나지 않습니다. WHEN SYSDATE < ofc.apply_start_date THEN '모집 대기' WHEN SYSDATE BETWEEN ofc.apply_start_date AND ofc.apply_end_date THEN '모집 중' WHEN SYSDATE BETWEEN ofc.apply_end_date AND ofc.course_start_date THEN '모집 마감' WHEN SYSDATE BETWEEN ofc.course_start_date AND ofc.course_end_date THEN '강의 진행 중' WHEN SYSDATE > ofc.course_end_date THEN '강의 종료' ELSE '상태 불명' END ELSE '유형 오류' END AS virtualStatus
FROM COURSE c LEFT OUTER JOIN ONLINE_COURSE onc ON c.course_id = onc.course_id LEFT OUTER JOIN OFFLINE_COURSE ofc ON c.course_id = ofc.course_id
-- 1. 공통 조건: HIDDEN(임시 숨김/비활성화) 강의 원천 제외 ( (c.course_type = 'ONLINE' AND NVL(onc.status, 'OPEN') != 'HIDDEN') OR (c.course_type = 'OFFLINE' AND NVL(ofc.status, 'OPEN') != 'HIDDEN') )
-- 2. 동적 쿼리: 카테고리 값이 파라미터로 넘어올 경우에만 AND 조건 추가
AND c.category_type = #{categoryType}
AND c.course_type IN
#{courseType}
AND EXISTS ( SELECT 1 FROM COURSE_SKILL cs WHERE cs.COURSE_ID = c.COURSE_ID AND cs.SKILL_ID IN
#{skillId}
)
ORDER BY ( SELECT COUNT(*) FROM COURSE_APPLICATION ca WHERE ca.COURSE_ID = c.COURSE_ID AND ca.APPLICATION_STATUS IN ('APPROVED', 'COMPLETED') ) DESC, c.course_id DESC
ORDER BY c.course_id DESC

SELECT c.course_id AS courseId, c.category_type AS categoryType, c.course_type AS courseType, c.course_title AS courseTitle, c.instructor_name AS instructorName, c.thumbnail_url AS thumbnailUrl, CASE WHEN c.course_type = 'ONLINE' THEN CASE WHEN onc.status = 'CANCELED' THEN '서비스 종료' ELSE '상시 수강 가능' END WHEN c.course_type = 'OFFLINE' THEN CASE WHEN ofc.status = 'CANCELED' THEN '폐강' WHEN SYSDATE < ofc.apply_start_date THEN '모집 대기' WHEN SYSDATE BETWEEN ofc.apply_start_date AND ofc.apply_end_date THEN '모집 중' WHEN SYSDATE BETWEEN ofc.apply_end_date AND ofc.course_start_date THEN '모집 마감' WHEN SYSDATE BETWEEN ofc.course_start_date AND ofc.course_end_date THEN '강의 진행 중' WHEN SYSDATE > ofc.course_end_date THEN '강의 종료' ELSE '상태 불명' END ELSE '유형 오류' END AS virtualStatus FROM COURSE c LEFT OUTER JOIN ONLINE_COURSE onc ON c.course_id = onc.course_id LEFT OUTER JOIN OFFLINE_COURSE ofc ON c.course_id = ofc.course_id
( (c.course_type = 'ONLINE' AND NVL(onc.status, 'OPEN') != 'HIDDEN') OR (c.course_type = 'OFFLINE' AND NVL(ofc.status, 'OPEN') != 'HIDDEN') )
AND c.category_type = #{categoryType}
AND c.course_type IN
#{courseType}
AND EXISTS ( SELECT 1 FROM COURSE_SKILL cs WHERE cs.COURSE_ID = c.COURSE_ID AND cs.SKILL_ID IN
#{skillId}
)
AND ( LOWER(c.course_title) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(c.instructor_name) LIKE '%' || LOWER(#{keyword}) || '%' )
AND ( (c.course_type = 'ONLINE' AND NVL(onc.status, 'OPEN') NOT IN ('CANCELED', 'HIDDEN')) OR ( c.course_type = 'OFFLINE' AND NVL(ofc.status, 'OPEN') NOT IN ('CANCELED', 'HIDDEN') AND SYSDATE BETWEEN ofc.apply_start_date AND ofc.apply_end_date AND NVL(ofc.current_applicant_count, 0) < NVL(ofc.capacity, 999999) ) )
ORDER BY ( SELECT COUNT(*) FROM COURSE_APPLICATION ca WHERE ca.COURSE_ID = c.COURSE_ID AND ca.APPLICATION_STATUS IN ('APPROVED', 'COMPLETED') ) DESC, c.CREATED_AT DESC, c.COURSE_ID DESC
ORDER BY c.CREATED_AT DESC, c.COURSE_ID DESC
OFFSET #{offset} ROWS FETCH NEXT #{limitPlusOne} ROWS ONLY

SELECT C.COURSE_ID AS courseId, C.CATEGORY_TYPE AS categoryType, C.COURSE_TYPE AS courseType, C.COURSE_TITLE AS courseTitle, C.DESCRIPTION AS description, C.INSTRUCTOR_NAME AS instructorName, C.TOTAL_DURATION_TIME AS totalDurationTime, C.THUMBNAIL_URL AS thumbnailUrl,
-- 온라인 강의 정보 ONL.COURSE_MATERIAL_URL AS courseMaterialUrl, ONL.STATUS AS onlineStatus,
-- 오프라인 강의 정보 OFF.CAPACITY AS capacity, OFF.CURRENT_APPLICANT_COUNT AS currentApplicantCount, OFF.LOCATION AS location, OFF.STATUS AS offlineStatus, OFF.APPLY_START_DATE AS applyStartDate, OFF.APPLY_END_DATE AS applyEndDate, OFF.COURSE_START_DATE AS courseStartDate, OFF.COURSE_END_DATE AS courseEndDate FROM COURSE C LEFT JOIN ONLINE_COURSE ONL ON C.COURSE_ID = ONL.COURSE_ID LEFT JOIN OFFLINE_COURSE OFF ON C.COURSE_ID = OFF.COURSE_ID WHERE C.COURSE_ID = #{courseId}

SELECT COUNT(1)
FROM COURSE_APPLICATION
WHERE user_id = #{userId}
  AND course_id = #{courseId}
  AND application_status IN ('WAITING', 'APPROVED')

mapper.update:
UPDATE COURSE_LEARNING_STATUS cls
SET progress_rate = (
        SELECT NVL(TRUNC(AVG(NVL(chs.progress_rate, 0))), 0)
        FROM COURSE_CHAPTER cc
        LEFT JOIN CHAPTER_LEARNING_STATUS chs
          ON chs.chapter_id = cc.chapter_id
         AND chs.course_learning_id = #{courseLearningId}
        WHERE cc.course_id = #{courseId}
          AND cc.use_yn = 'Y'
    ),
    updated_at = SYSDATE
WHERE cls.course_learning_id = #{courseLearningId}

mapper.select:
SELECT COUNT(*)
FROM COURSE_LEARNING_STATUS
WHERE user_id = #{userId}
  AND status = #{status}
